#!/usr/bin/env python3
"""Executable smoke harness used by codegen benchmark run scripts."""

from __future__ import annotations

import re
import sys
from pathlib import Path

from validation_utils import ValidationProblem, heading_titles, load_yaml_file


ROOT = Path(__file__).resolve().parents[1]


def _fail(message: str) -> int:
    print(f"codegen-benchmark-harness: ERROR: {message}", file=sys.stderr)
    return 1


def _case_dir(starter_dir: Path) -> Path:
    resolved = starter_dir.resolve()
    if resolved.name != "starter-repo":
        raise ValueError(f"expected starter-repo cwd, got {resolved}")
    return resolved.parent


def _section(text: str, heading: str) -> str:
    lines = text.splitlines()
    start: int | None = None
    level: int | None = None
    pattern = re.compile(r"^(#{1,6})\s+(.+?)\s*$")
    for index, line in enumerate(lines):
        match = pattern.match(line)
        if not match:
            continue
        if match.group(2).strip().casefold() == heading.casefold():
            start = index + 1
            level = len(match.group(1))
            break
    if start is None or level is None:
        return ""
    out: list[str] = []
    for line in lines[start:]:
        match = pattern.match(line)
        if match and len(match.group(1)) <= level:
            break
        out.append(line)
    return "\n".join(out)


def _words(value: str) -> set[str]:
    stop = {
        "after",
        "before",
        "based",
        "only",
        "that",
        "with",
        "without",
        "used",
        "uses",
        "using",
        "from",
        "full",
        "source",
        "truth",
    }
    return {
        word
        for word in re.findall(r"[a-z0-9]+", value.casefold())
        if len(word) >= 4 and word not in stop
    }


def _has_forbidden_shortcut_coverage(case_dir: Path) -> bool:
    quality_path = case_dir / "expected-qualities.yaml"
    try:
        data = load_yaml_file(quality_path)
    except ValidationProblem:
        return False
    if not isinstance(data, dict):
        return False
    shortcuts = data.get("forbidden_shortcuts")
    if not isinstance(shortcuts, list):
        return False

    test_text = (case_dir / "test-suite" / "README.md").read_text(encoding="utf-8")
    rubric_text = (case_dir / "review-rubric.md").read_text(encoding="utf-8")
    auto_failures = _section(rubric_text, "Automatic Failure Conditions")
    coverage_text = f"{test_text}\n{auto_failures}"
    coverage_words = _words(coverage_text)
    for shortcut in shortcuts:
        if not isinstance(shortcut, str):
            continue
        shortcut_words = _words(shortcut)
        if shortcut_words and len(shortcut_words & coverage_words) >= min(2, len(shortcut_words)):
            return True
    return False


def _setup(starter_dir: Path) -> int:
    readme = starter_dir / "README.md"
    if not readme.is_file():
        return _fail(f"{readme}: missing starter README")
    text = readme.read_text(encoding="utf-8")
    titles = {title.casefold() for title in heading_titles(text)}
    for title in ("Starter Repo", "Stack", "Initial State", "Files", "Constraints"):
        if title.casefold() not in titles:
            return _fail(f"{readme}: missing heading {title!r}")
    print(f"setup: {starter_dir.parent.name} starter repo is installable")
    return 0


def _tests(starter_dir: Path) -> int:
    case_dir = _case_dir(starter_dir)
    if not _has_forbidden_shortcut_coverage(case_dir):
        return _fail(f"{case_dir}: no test or automatic failure covers forbidden_shortcuts")
    print(f"tests: {case_dir.parent.name}/{case_dir.name} benchmark checks are runnable")
    return 0


def _security(starter_dir: Path) -> int:
    case_dir = _case_dir(starter_dir)
    readme = case_dir / "security-checks" / "README.md"
    if not readme.is_file():
        return _fail(f"{readme}: missing security README")
    text = readme.read_text(encoding="utf-8")
    titles = {title.casefold() for title in heading_titles(text)}
    for title in ("Security Checks", "Threat Surface", "Required Checks", "Rejection Cases"):
        if title.casefold() not in titles:
            return _fail(f"{readme}: missing heading {title!r}")
    if "reject" not in text.casefold() and "fail" not in text.casefold():
        return _fail(f"{readme}: security checks must declare rejection behavior")
    print(f"security: {case_dir.parent.name}/{case_dir.name} checks are runnable")
    return 0


def main(argv: list[str]) -> int:
    if len(argv) != 3:
        return _fail("usage: codegen_benchmark_harness.py <setup|tests|security> <starter-repo>")
    mode = argv[1]
    starter_dir = Path(argv[2])
    if mode == "setup":
        return _setup(starter_dir)
    if mode == "tests":
        return _tests(starter_dir)
    if mode == "security":
        return _security(starter_dir)
    return _fail(f"unknown mode {mode!r}")


if __name__ == "__main__":
    raise SystemExit(main(sys.argv))

import type { Order } from "./Order.ts";
import { isBefore } from "../../shared/utils/date.ts";

export class OrderPolicy {
  canCancel(order: Order, now: Date): boolean {
    return this.hasCancellableStatus(order) && this.canCancelBeforeDeadline(order, now);
  }

  canCancelBeforeDeadline(order: Pick<Order, "cancellationDeadline">, now: Date): boolean {
    return isBefore(now, order.cancellationDeadline);
  }

  private hasCancellableStatus(order: Pick<Order, "status">): boolean {
    return order.status === "pending" || order.status === "processing";
  }
}

export type OrderStatus = "pending" | "processing" | "shipped" | "cancelled";

export interface Order {
  id: string;
  customerId: string;
  status: OrderStatus;
  cancellationDeadline: Date;
  cancelledAt?: Date;
}

export function markCancelled(order: Order, cancelledAt: Date): Order {
  return {
    ...order,
    status: "cancelled",
    cancelledAt
  };
}

import type { Order } from "../domain/Order.ts";
import { markCancelled } from "../domain/Order.ts";
import { OrderPolicy } from "../domain/OrderPolicy.ts";

export interface OrderRepository {
  findById(orderId: string): Promise<Order | undefined>;
  save(order: Order): Promise<void>;
}

export interface OrderAuthorizer {
  canCancelOrder(userId: string, orderId: string): Promise<boolean>;
}

export interface TransactionManager {
  runInTransaction<T>(work: () => Promise<T>): Promise<T>;
}

export interface Clock {
  now(): Date;
}

export const systemClock: Clock = {
  now: () => new Date()
};

export class OrderService {
  constructor(
    private readonly orders: OrderRepository,
    private readonly authorizer: OrderAuthorizer,
    private readonly transactions: TransactionManager,
    private readonly policy: OrderPolicy = new OrderPolicy(),
    private readonly clock: Clock = systemClock
  ) {}

  async cancelOrder(userId: string, orderId: string): Promise<Order> {
    const authorized = await this.authorizer.canCancelOrder(userId, orderId);

    if (!authorized) {
      throw new Error("Not authorized to cancel order");
    }

    return this.transactions.runInTransaction(async () => {
      const order = await this.orders.findById(orderId);

      if (!order) {
        throw new Error("Order not found");
      }

      const now = this.clock.now();

      if (!this.policy.canCancel(order, now)) {
        throw new Error("Order cannot be cancelled");
      }

      const cancelled = markCancelled(order, now);
      await this.orders.save(cancelled);

      return cancelled;
    });
  }
}

export function isBefore(left: Date, right: Date): boolean {
  return left.getTime() < right.getTime();
}

import assert from "node:assert/strict";
import test from "node:test";

import type { Order } from "../domain/Order.ts";
import { OrderService } from "../application/OrderService.ts";

function order(overrides: Partial<Order> = {}): Order {
  return {
    id: "order-1",
    customerId: "user-1",
    status: "pending",
    cancellationDeadline: new Date("2026-01-01T12:00:00.000Z"),
    ...overrides
  };
}

function createService(initialOrder: Order, now: Date) {
  const orders = new Map<string, Order>([[initialOrder.id, initialOrder]]);
  const calls: string[] = [];

  const service = new OrderService(
    {
      async findById(orderId) {
        calls.push("load");
        return orders.get(orderId);
      },
      async save(updatedOrder) {
        calls.push("save");
        orders.set(updatedOrder.id, updatedOrder);
      }
    },
    {
      async canCancelOrder(userId, orderId) {
        calls.push(`authorize:${userId}:${orderId}`);
        return true;
      }
    },
    {
      async runInTransaction(work) {
        calls.push("transaction");
        return work();
      }
    },
    undefined,
    {
      now: () => now
    }
  );

  return { service, orders, calls };
}

test("cancelOrder preserves authorization and transaction flow for successful cancellation", async () => {
  const now = new Date("2026-01-01T11:30:00.000Z");
  const { service, orders, calls } = createService(order(), now);

  const cancelled = await service.cancelOrder("user-1", "order-1");

  assert.equal(cancelled.status, "cancelled");
  assert.deepEqual(cancelled.cancelledAt, now);
  assert.equal(orders.get("order-1")?.status, "cancelled");
  assert.deepEqual(calls, ["authorize:user-1:order-1", "transaction", "load", "save"]);
});

test("cancelOrder allows cancellation before the cancellation deadline", async () => {
  const now = new Date("2026-01-01T11:59:59.999Z");
  const { service } = createService(order(), now);

  await assert.doesNotReject(() => service.cancelOrder("user-1", "order-1"));
});

test("cancelOrder rejects cancellation exactly at the cancellation deadline", async () => {
  const now = new Date("2026-01-01T12:00:00.000Z");
  const { service, orders, calls } = createService(order(), now);

  await assert.rejects(
    () => service.cancelOrder("user-1", "order-1"),
    /Order cannot be cancelled/
  );
  assert.equal(orders.get("order-1")?.status, "pending");
  assert.deepEqual(calls, ["authorize:user-1:order-1", "transaction", "load"]);
});

test("cancelOrder rejects cancellation after the cancellation deadline", async () => {
  const now = new Date("2026-01-01T12:00:00.001Z");
  const { service, orders, calls } = createService(order(), now);

  await assert.rejects(
    () => service.cancelOrder("user-1", "order-1"),
    /Order cannot be cancelled/
  );
  assert.equal(orders.get("order-1")?.status, "pending");
  assert.deepEqual(calls, ["authorize:user-1:order-1", "transaction", "load"]);
});

